const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let results = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const K = input[idx++];
  const arr = input.slice(idx, idx + N);
  idx += N;
  arr.sort((a, b) => b - a);
  let sumFirst = 0;
  for (let i = 0; i < K; i++) sumFirst += arr[2 * i];
  let sumSecond = 0;
  for (let i = 0; i < K - 1; i++) sumSecond += arr[2 * i + 1];
  sumSecond += arr[2 * K - 1] + arr[2 * K];
  results.push(String(Math.max(sumFirst, sumSecond)));
}
console.log(results.join('\n'));
